#include <math.h>
#include <omp.h>

#include "./main.h"
#include "./kernel/kernel_cpu.h"

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    long bx, i, j, k;

    omp_set_num_threads(dim.cores_arg);

    #pragma omp parallel for private(bx, i, j, k) schedule(static)
    for (bx = 0; bx < dim.number_boxes; bx++) {

        fp a2 = 2.0 * par.alpha * par.alpha;

        int first_i = box[bx].offset;
        FOUR_VECTOR* rA = &rv[first_i];
        FOUR_VECTOR* fA = &fv[first_i];

        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
        for (i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            rA_shared[i] = rA[i];
        }

        for (k = 0; k < (1 + box[bx].nn); k++) {

            int pointer;
            if (k == 0) {
                pointer = (int)bx;
            } else {
                pointer = box[bx].nei[k - 1].number;
            }

            int first_j = box[pointer].offset;
            FOUR_VECTOR* rB = &rv[first_j];
            fp* qB = &qv[first_j];

            FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
            fp qB_shared[NUMBER_PAR_PER_BOX];

            for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                rB_shared[j] = rB[j];
                qB_shared[j] = qB[j];
            }

            for (i = 0; i < NUMBER_PAR_PER_BOX; i++) {
                for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    fp r2 = (fp)rA_shared[i].v + (fp)rB_shared[j].v
                            - DOT(((FOUR_VECTOR){(fp)rA_shared[i].v, (fp)rA_shared[i].x, (fp)rA_shared[i].y, (fp)rA_shared[i].z}),
                                  ((FOUR_VECTOR){(fp)rB_shared[j].v, (fp)rB_shared[j].x, (fp)rB_shared[j].y, (fp)rB_shared[j].z}));
                    fp u2 = a2 * r2;
                    fp vij = exp(-u2);
                    fp fs = 2 * vij;

                    THREE_VECTOR d;
                    d.x = (fp)rA_shared[i].x - (fp)rB_shared[j].x;
                    fp fxij = fs * d.x;
                    d.y = (fp)rA_shared[i].y - (fp)rB_shared[j].y;
                    fp fyij = fs * d.y;
                    d.z = (fp)rA_shared[i].z - (fp)rB_shared[j].z;
                    fp fzij = fs * d.z;

                    fA[i].v += (double)((fp)qB_shared[j] * vij);
                    fA[i].x += (double)((fp)qB_shared[j] * fxij);
                    fA[i].y += (double)((fp)qB_shared[j] * fyij);
                    fA[i].z += (double)((fp)qB_shared[j] * fzij);
                }
            }
        }
    }
}
